	var (
		result  gitsync.SyncResult
		lastErr error
		attempt int
	)
	for attempt = 1; attempt <= maxSyncAttempts; attempt++ {
		if attempt > 1 {
			select {
			case <-ctx.Done():
				span.SetAttributes(attribute.Int("entire.sync.attempts", attempt-1))
				classified := transientErr(ctx.Err())
				span.RecordError(classified)
				span.SetStatus(otelcodes.Error, "context canceled during retry backoff")
				return classified
			case <-time.After(syncRetryDelay):
			}
		}

		result, err = client.Replicate(ctx, gitsync.SyncRequest{
			Source: gitsync.Endpoint{URL: sourceURL},
			// FollowInfoRefsRedirect carries the 307 from a non-hosting
			// entiredb node into the endpoint, so the subsequent
			// receive-pack POST lands on the hosting replica instead of
			// the originally-configured host. No-op for the current
			// node-specific ENTIRE_TARGET_URL (node1 either hosts or
			// serves via DISS), but lets us flip fleet to the cluster
			// entry domain without a code change.
			Target: gitsync.Endpoint{URL: targetURL, FollowInfoRefsRedirect: true},
			Scope: gitsync.RefScope{
				AllRefs: true,
				// refs/pull/* is GitHub's PR ref namespace — skip mirroring it
				// to avoid surfacing source-side PR state on the mirror.
				//
				// The remaining prefixes mirror entire-server's reserved-push
				// denylist (isReservedPushRef in server/githttp/receive_pack.go):
				// git-receive-pack returns 403 "push to <ref> is not allowed"
				// for any of these namespaces. Under AllRefs we faithfully copy
				// whatever the source advertises, so a stray ref like
				// refs/remotes/origin/* accidentally pushed up to a source repo
				// would otherwise fail the entire sync permanently. Excluding
				// the prefixes here means we neither read them from the source
				// nor try to push/prune them on the target.
				//
				// refs/tlog/* is entiredb-owned (commit-tlog state appended by
				// entire-server on its receive-pack hook); direct pushes are
				// rejected with "use sync instead".
				ExcludeRefPrefixes: []string{
					"refs/pull/",
					"refs/tlog/",
					"refs/remotes/",
					"refs/internal/",
					"refs/replace/",
					"refs/bisect/",
					"refs/meta/",
					"refs/namespaces/",
					"refs/stash", // covers the exact refs/stash ref and refs/stash/*
				},
			},
			Policy: gitsync.SyncPolicy{
				IncludeTags: true,
				Prune:       true,
			},
		})
		if err == nil {
			lastErr = nil
			break
		}
		lastErr = err
		if !isTransientGitFetchError(err) {
			break
		}
		if attempt >= maxSyncAttempts {
			break
		}
		slog.WarnContext(ctx, "Transient git-fetch failure; will retry",
			slog.Int("attempt", attempt),
			slog.Int("max_attempts", maxSyncAttempts),
			slog.Any("error", redactAuth(err)),
		)
	}

	span.SetAttributes(attribute.Int("entire.sync.attempts", attempt))

	if lastErr != nil {
		// An empty source (no refs to mirror) is a clean no-op, not a failure:
		// don't record it as a span error and signal the noop disposition so
		// disposeResult acks rather than redelivering a job that can only
		// repeat the same no-op against an unchanged empty source.
		if isNoSourceRefsError(lastErr) {
			span.SetAttributes(attribute.Bool("entire.sync.noop", true))
			span.SetStatus(otelcodes.Ok, "source has no refs to mirror")
			slog.InfoContext(ctx, "Sync no-op: source has no refs to mirror",
				slog.String("source_owner", req.SourceOwner),
				slog.String("source_repo", req.SourceRepo),
				slog.String("target_ulid", req.TargetULID),
			)
			return errSourceNoRefs
		}
		classified := classifySyncError(redactAuth(lastErr))
		span.RecordError(classified)
		span.SetStatus(otelcodes.Error, "sync from github")
		return classified
	}

