// streamSeq returns the message's JetStream stream sequence, or 0 if metadata
// is unavailable (e.g. a synthetic test message). Used as the failure-index
// dedup token and the clear-on-success ordering guard.
func streamSeq(msg ackableMsg) uint64 {
	if meta, err := msg.Metadata(); err == nil {
		return meta.Sequence.Stream
	}
	return 0
}

// isLastDelivery reports whether this is the final delivery before JetStream
// stops redelivering (NumDelivered has reached consumerMaxDeliver).
func isLastDelivery(msg ackableMsg) bool {
	if meta, err := msg.Metadata(); err == nil {
		return meta.NumDelivered >= consumerMaxDeliver
	}
	return false
}

// recordTerminal makes a BEST-EFFORT write of a terminal failure to the KV
// index. It never gates the caller's disposal: on a KV write failure it fails
// open — logs and increments record_failed{cause}, and the caller Terms the
// message anyway rather than Nak-ing. A KV outage must not wedge the consumer or
// burn re-sync retries (the record-failure paths are permanent/validation/
// exhausted, where a re-sync is wasted or moot). Recovery of a dropped record is
// owned by the record_failed alert and the L2 reconcile, not by holding the
// message.
func (c *consumer) recordTerminal(ctx context.Context, ulid, subject string, payload []byte, seq uint64, reason failindex.FailureReason, source string, cause error) {
	if c.failidx == nil {
		// Index unbound — cannot capture this terminal failure. Surface it
		// (depth/recorded stay flat otherwise); the caller Terms regardless.
		c.metrics.recordIndexUnavailable(ctx, failedIndexCauseUnbound)
		return
	}
	if ulid == "" {
		return // unreachable post-Unmarshal/Validate; defensive
