package main

import (
	"errors"
	"fmt"
	"testing"

	gitsync "entire.io/entire/git-sync"
	"github.com/go-git/go-git/v6/plumbing"
	"github.com/go-git/go-git/v6/plumbing/protocol/packp"
)

// Reproduces exactly what go-git hands git-sync's sendReceivePack:
// report.Error() -> CommandStatus.Error() -> a VALUE-typed packp.CommandStatusErr.
func TestZZ_BlockerRepro_CommandStatusErrIsValueTyped(t *testing.T) {
	cs := &packp.CommandStatus{
		ReferenceName: plumbing.ReferenceName("refs/heads/main"),
		Status:        "remote ref has changed",
	}
	err := cs.Error() // exactly what report.Error() returns to git-sync
	if err == nil {
		t.Fatal("expected a non-nil command status error")
	}
	t.Logf("dynamic type of report.Error() = %T", err)

	// (1) git-sync's asRefRejectedError / annotateLeaseFailure use a POINTER target:
	//     var cs *packp.CommandStatusErr; errors.As(err, &cs)
	var asPtr *packp.CommandStatusErr
	matchedPtr := errors.As(err, &asPtr)
	t.Logf("errors.As(err, **CommandStatusErr) = %v  (git-sync's actual target)", matchedPtr)

	// (2) The fix: a VALUE target.
	var asVal packp.CommandStatusErr
	matchedVal := errors.As(err, &asVal)
	t.Logf("errors.As(err, *CommandStatusErr) = %v   (the corrected target)", matchedVal)

	// Now run the EXACT git-sync asRefRejectedError logic (copied verbatim) and
	// confirm errors.Is(ErrTargetRefMoved) is false on the real path.
	wrapped := fmt.Errorf("report-status: %w", asRefRejectedErrorRepro(err))
	racedDetected := errors.Is(wrapped, gitsync.ErrTargetRefMoved)
	t.Logf("errors.Is(wrapped, gitsync.ErrTargetRefMoved) = %v", racedDetected)

	if matchedPtr {
		t.Errorf("UNEXPECTED: pointer-target errors.As matched — blocker would NOT hold")
	}
	if !matchedVal {
		t.Errorf("UNEXPECTED: value-target errors.As did not match — fix would not work")
	}
	if racedDetected {
		t.Errorf("UNEXPECTED: sentinel detected on real path — blocker would NOT hold")
	}
}

// asRefRejectedErrorRepro is a verbatim copy of git-sync's asRefRejectedError
// (vendor/.../internal/gitproto/push.go:238) using the SAME pointer target, to
// prove behavior without reaching into the internal package.
func asRefRejectedErrorRepro(err error) error {
	var cs *packp.CommandStatusErr
	if !errors.As(err, &cs) {
		return err // <-- git-sync returns here: no RefRejectedError, no moved=true
	}
	return gitsync.RefRejectedError{Ref: cs.ReferenceName.String(), Reason: cs.Status}
}

